  "WW·01": "<svg viewbox=\"0 0 100 100\" xmlns=\"http://www.w3.org/2000/svg\">\n<circle cx=\"50\" cy=\"50\" fill=\"rgba(122,0,0,0.08)\" r=\"42\" stroke=\"#7A0000\" stroke-width=\"1.5\"></circle>\n<!-- Distressed Blood Moon -->\n<circle cx=\"50\" cy=\"45\" fill=\"#a31515\" opacity=\"0.4\" r=\"24\"></circle>\n<path d=\"M60,30 A24,24 0 0,0 35,55 A24,24 0 0,1 60,30\" fill=\"#7A0000\" opacity=\"0.6\"></path>\n<!-- Sharp Ears -->\n<polygon fill=\"#111\" points=\"32,25 40,40 30,45\"></polygon>\n<polygon fill=\"#111\" points=\"68,25 60,40 70,45\"></polygon>\n<!-- Fur top -->\n<polygon fill=\"#1a1a1a\" points=\"35,40 50,32 65,40\"></polygon>\n<polygon fill=\"#222\" points=\"40,40 50,20 60,40\"></polygon>\n<!-- Face structure -->\n<polygon fill=\"#111\" points=\"30,45 50,42 70,45 65,65 50,80 35,65\"></polygon>\n<polygon fill=\"#222\" points=\"38,45 50,45 50,75 35,60\"></polygon>\n<polygon fill=\"#171717\" points=\"62,45 50,45 50,75 65,60\"></polygon>\n<!-- Snout & Nose -->\n<polygon fill=\"#000\" points=\"45,65 55,65 50,75\"></polygon>\n<!-- Fierce Eyes -->\n<polygon fill=\"#FF1A1A\" points=\"38,50 45,52 42,48\"></polygon>\n<polygon fill=\"#FF1A1A\" points=\"62,50 55,52 58,48\"></polygon>\n<!-- Eye glow -->\n<circle cx=\"41.5\" cy=\"50\" fill=\"#FFD700\" r=\"1.5\"></circle>\n<circle cx=\"58.5\" cy=\"50\" fill=\"#FFD700\" r=\"1.5\"></circle>\n<!-- Fangs / Jaw -->\n<polygon fill=\"#e6e6e6\" points=\"45,78 47,85 50,80 53,85 55,78\"></polygon>\n</svg>",
  "WW·02": "<svg viewbox=\"0 0 100 100\" xmlns=\"http://www.w3.org/2000/svg\">\n<circle cx=\"50\" cy=\"50\" fill=\"rgba(122,0,0,0.08)\" r=\"42\" stroke=\"#7A0000\" stroke-width=\"1.5\"></circle>\n<!-- Distressed Blood Moon -->\n<circle cx=\"50\" cy=\"45\" fill=\"#a31515\" opacity=\"0.4\" r=\"24\"></circle>\n<path d=\"M60,30 A24,24 0 0,0 35,55 A24,24 0 0,1 60,30\" fill=\"#7A0000\" opacity=\"0.6\"></path>\n<!-- Sharp Ears -->\n<polygon fill=\"#111\" points=\"32,25 40,40 30,45\"></polygon>\n<polygon fill=\"#111\" points=\"68,25 60,40 70,45\"></polygon>\n<!-- Fur top -->\n<polygon fill=\"#1a1a1a\" points=\"35,40 50,32 65,40\"></polygon>\n<polygon fill=\"#222\" points=\"40,40 50,20 60,40\"></polygon>\n<!-- Face structure -->\n<polygon fill=\"#111\" points=\"30,45 50,42 70,45 65,65 50,80 35,65\"></polygon>\n<polygon fill=\"#222\" points=\"38,45 50,45 50,75 35,60\"></polygon>\n<polygon fill=\"#171717\" points=\"62,45 50,45 50,75 65,60\"></polygon>\n<!-- Snout & Nose -->\n<polygon fill=\"#000\" points=\"45,65 55,65 50,75\"></polygon>\n<!-- Fierce Eyes -->\n<polygon fill=\"#FF1A1A\" points=\"38,50 45,52 42,48\"></polygon>\n<polygon fill=\"#FF1A1A\" points=\"62,50 55,52 58,48\"></polygon>\n<!-- Eye glow -->\n<circle cx=\"41.5\" cy=\"50\" fill=\"#FFD700\" r=\"1.5\"></circle>\n<circle cx=\"58.5\" cy=\"50\" fill=\"#FFD700\" r=\"1.5\"></circle>\n<!-- Fangs / Jaw -->\n<polygon fill=\"#e6e6e6\" points=\"45,78 47,85 50,80 53,85 55,78\"></polygon>\n</svg>",
  "WW·03": "<svg viewbox=\"0 0 100 100\" xmlns=\"http://www.w3.org/2000/svg\">\n<circle cx=\"50\" cy=\"50\" fill=\"rgba(122,0,0,0.08)\" r=\"42\" stroke=\"#7A0000\" stroke-width=\"1.5\"></circle>\n<!-- Blood Moon -->\n<circle cx=\"50\" cy=\"45\" fill=\"#a31515\" opacity=\"0.4\" r=\"24\"></circle>\n<path d=\"M60,30 A24,24 0 0,0 35,55 A24,24 0 0,1 60,30\" fill=\"#7A0000\" opacity=\"0.6\"></path>\n<!-- Sharp Ears -->\n<polygon fill=\"#222\" points=\"32,25 40,40 30,45\"></polygon>\n<polygon fill=\"#222\" points=\"68,25 60,40 70,45\"></polygon>\n<!-- Fur top -->\n<polygon fill=\"#333\" points=\"35,40 50,32 65,40\"></polygon>\n<polygon fill=\"#444\" points=\"40,40 50,20 60,40\"></polygon>\n<!-- Face structure -->\n<polygon fill=\"#111\" points=\"30,45 50,42 70,45 65,65 50,80 35,65\"></polygon>\n<polygon fill=\"#222\" points=\"38,45 50,45 50,75 35,60\"></polygon>\n<polygon fill=\"#171717\" points=\"62,45 50,45 50,75 65,60\"></polygon>\n<!-- Snout & Nose -->\n<polygon fill=\"#000\" points=\"45,65 55,65 50,75\"></polygon>\n<!-- Fierce Eyes Alpha (Gold/Yellow) -->\n<polygon fill=\"#FFD700\" points=\"38,50 45,52 42,48\"></polygon>\n<polygon fill=\"#FFD700\" points=\"62,50 55,52 58,48\"></polygon>\n<!-- Eye glow -->\n<circle cx=\"41.5\" cy=\"50\" fill=\"#FFF\" r=\"1.5\"></circle>\n<circle cx=\"58.5\" cy=\"50\" fill=\"#FFF\" r=\"1.5\"></circle>\n<!-- Fangs / Jaw -->\n<polygon fill=\"#e6e6e6\" points=\"45,78 47,85 50,80 53,85 55,78\"></polygon>\n<!-- Golden Crown of the Alpha -->\n<polygon fill=\"#FFD700\" points=\"25,25 20,5 35,15 50,2 65,15 80,5 75,25\" stroke=\"#B8860B\" stroke-width=\"1.5\"></polygon>\n<circle cx=\"20\" cy=\"5\" fill=\"#DC143C\" r=\"3\"></circle>\n<circle cx=\"50\" cy=\"2\" fill=\"#DC143C\" r=\"4\"></circle>\n<circle cx=\"80\" cy=\"5\" fill=\"#DC143C\" r=\"3\"></circle>\n<polygon fill=\"#B8860B\" points=\"25,28 75,28 72,32 28,32\"></polygon>\n</svg>",
  "WW·04": "<svg viewbox=\"0 0 100 100\" xmlns=\"http://www.w3.org/2000/svg\">\n<circle cx=\"50\" cy=\"50\" fill=\"rgba(122,0,0,0.08)\" r=\"42\" stroke=\"#7A0000\" stroke-width=\"1.5\"></circle>\n<!-- Left: Human half (Noble profile) -->\n<path d=\"M50,15 C30,15 20,35 25,60 C28,75 40,85 50,85 Z\" fill=\"#f5d7b5\"></path>\n<!-- Human Hair -->\n<path d=\"M50,15 C30,15 20,30 22,45 C28,30 40,25 50,25 Z\" fill=\"#4a3623\"></path>\n<!-- Human Eye & Brow -->\n<path d=\"M35,45 Q40,42 45,45\" fill=\"none\" stroke=\"#222\" stroke-width=\"1.5\"></path>\n<circle cx=\"38\" cy=\"48\" fill=\"#fff\" r=\"2.5\"></circle>\n<circle cx=\"38\" cy=\"48\" fill=\"#333\" r=\"1\"></circle>\n<!-- Human Nose & Mouth profile illusion -->\n<path d=\"M45,65 Q48,68 50,68\" fill=\"none\" stroke=\"#d2a66b\" stroke-width=\"1.5\"></path>\n<!-- Right: Wolf half (Fierce profile) -->\n<path d=\"M50,15 C70,15 85,30 80,55 C78,75 60,85 50,85 Z\" fill=\"#111\"></path>\n<polygon fill=\"#111\" points=\"50,15 65,10 60,25\"></polygon>\n<polygon fill=\"#222\" points=\"80,55 90,60 78,65\"></polygon>\n<!-- Wolf Eye -->\n<path d=\"M55,44 Q60,40 68,46\" fill=\"none\" stroke=\"#222\" stroke-width=\"1.5\"></path>\n<polygon fill=\"#FF1A1A\" points=\"58,47 64,45 64,49 Z\"></polygon>\n<circle cx=\"61\" cy=\"47\" fill=\"#FFD700\" r=\"1.2\"></circle>\n<!-- Wolf Snout -->\n<path d=\"M50,70 Q60,70 70,75\" fill=\"none\" stroke=\"#333\" stroke-width=\"1.5\"></path>\n<polygon fill=\"#fff\" points=\"55,72 60,78 52,78\"></polygon>\n<!-- Split Line Glow -->\n<line stroke=\"#7A0000\" stroke-dasharray=\"6,4\" stroke-width=\"1.5\" x1=\"50\" x2=\"50\" y1=\"10\" y2=\"90\"></line>\n<line opacity=\"0.6\" stroke=\"#ff4d4d\" stroke-width=\"0.5\" x1=\"49\" x2=\"49\" y1=\"10\" y2=\"90\"></line>\n</svg>",
  "WW·05": "<svg viewbox=\"0 0 100 100\" xmlns=\"http://www.w3.org/2000/svg\">\n<circle cx=\"50\" cy=\"50\" fill=\"rgba(122,0,0,0.08)\" r=\"42\" stroke=\"#7A0000\" stroke-width=\"1.5\"></circle>\n<!-- Giant Pale Moon -->\n<circle cx=\"50\" cy=\"50\" fill=\"#e6e6e6\" r=\"32\"></circle>\n<circle cx=\"40\" cy=\"40\" fill=\"#cccccc\" opacity=\"0.6\" r=\"6\"></circle>\n<circle cx=\"65\" cy=\"60\" fill=\"#cccccc\" opacity=\"0.6\" r=\"8\"></circle>\n<circle cx=\"60\" cy=\"35\" fill=\"#cccccc\" opacity=\"0.6\" r=\"4\"></circle>\n<!-- Lone Wolf howling silhouette on rocky crag -->\n<path d=\"M10,85 L45,70 L90,85 Z\" fill=\"#111\"></path>\n<!-- Wolf Howling -->\n<path d=\"M35,75 C35,60 40,40 50,30 C53,27 57,22 55,18 C58,20 62,25 65,22 C62,28 65,32 60,38 C55,42 55,50 65,65 C68,70 70,75 65,75 Z\" fill=\"#111\"></path>\n<polygon fill=\"#111\" points=\"52,28 48,22 50,28\"></polygon> <!-- ear -->\n</svg>",
